challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The Access and Mobility Management Function (AMF) has terminated unexpectedly. As the core control-plane function for registration and session management, its failure has halted all PDU session establishment, leading to a complete loss of data plane connectivity.",
      "primary_suspect_nf": "amf",
      "probes": [
        {
          "tool": "get_network_status",
          "args_hint": "Check the container status for 'amf'",
          "expected_if_hypothesis_holds": "The 'amf' container has a status of 'exited' or is not listed among running containers.",
          "falsifying_observation": "The 'amf' container is in a 'running' state. This would directly contradict the hypothesis that it has terminated."
        },
        {
          "tool": "check_process_listeners",
          "args_hint": "Check listening ports on the 'amf' container.",
          "expected_if_hypothesis_holds": "The command returns no output or an error, indicating no processes are listening for traffic, which is expected if the AMF has terminated.",
          "falsifying_observation": "A process is actively listening on the AMF's NGAP SCTP port (38412). This would imply the AMF process is alive and has initialized its network interfaces, contradicting the hypothesis."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "Measure RTT from the 'nr_gnb' container to the IP of the 'amf' container.",
          "expected_if_hypothesis_holds": "100% packet loss. An offline container cannot respond to pings.",
          "falsifying_observation": "A clean RTT (< 5ms) is measured. This would prove the AMF container is online and network-reachable from the RAN, falsifying the hypothesis."
        }
      ],
      "notes": "This plan directly tests the core assertion of the hypothesis: the unexpected termination of the AMF container. The probes verify the container's runtime state, its process-level network initialization, and its network reachability from the RAN. If the AMF is running and reachable, this hypothesis is false."
    }
  ]
}

